package examples.simple.org.apache.accumulo.examples.simple.helloworld;

public class InsertWithBatchWriter { public static void main ( String [ ] args ) throws AccumuloException , AccumuloSecurityException , MutationsRejectedException , TableExistsException , TableNotFoundException { ClientOnRequiredTable opts = new ClientOnRequiredTable ( ) ; BatchWriterOpts bwOpts = new BatchWriterOpts ( ) ; opts . parseArgs ( InsertWithBatchWriter . class . getName ( ) , args , bwOpts ) ; Connector connector = opts . getConnector ( ) ; MultiTableBatchWriter mtbw = connector . createMultiTableBatchWriter ( bwOpts . getBatchWriterConfig ( ) ) ; if ( ! connector . tableOperations ( ) . exists ( opts . getTableName ( ) ) ) connector . tableOperations ( ) . create ( opts . getTableName ( ) ) ; BatchWriter bw = mtbw . getBatchWriter ( opts . getTableName ( ) ) ; Text colf = new Text ( "colfam" ) ; System . out . println ( "writing ..." ) ; for ( int i = 0 ; i < 10000 ; i ++ ) { Mutation m = new Mutation ( new Text ( String . format ( "row_%d" , i ) ) ) ; for ( int j = 0 ; j < 5 ; j ++ ) { m . put ( colf , new Text ( String . format ( "colqual_%d" , j ) ) , new Value ( ( String . format ( "value_%d_%d" , i , j ) ) . getBytes ( ) ) ) ; } bw . addMutation ( m ) ; if ( i % 100 == 0 ) System . out . println ( i ) ; } mtbw . close ( ) ; } }